import { Union, Record } from "./.fable/fable-library.3.0.1/Types.js";
import { Router_navigatePage, PageModule_parseFromUrlSegments, Page$reflection } from "./Router.js";
import { union_type, record_type } from "./.fable/fable-library.3.0.1/Reflection.js";
import { RouterModule_urlSegments } from "./.fable/Feliz.Router.3.3.0/Router.fs.js";
import { Cmd_none, Cmd_ofSub } from "./.fable/Fable.Elmish.3.1.0/cmd.fs.js";

export class Model extends Record {
    constructor(CurrentPage) {
        super();
        this.CurrentPage = CurrentPage;
    }
}

export function Model$reflection() {
    return record_type("DzoukrCz.Client.State.Model", [], Model, () => [["CurrentPage", Page$reflection()]]);
}

export class Msg extends Union {
    constructor(tag, ...fields) {
        super();
        this.tag = (tag | 0);
        this.fields = fields;
    }
    cases() {
        return ["UrlChanged"];
    }
}

export function Msg$reflection() {
    return union_type("DzoukrCz.Client.State.Msg", [], Msg, () => [[["currentPage", Page$reflection()]]]);
}

export function init() {
    const nextPage = PageModule_parseFromUrlSegments(RouterModule_urlSegments(window.location.pathname + window.location.search, 2));
    return [new Model(nextPage), Cmd_ofSub((_arg1_1) => {
        Router_navigatePage(nextPage);
    })];
}

export function update(msg, model) {
    return [new Model(msg.fields[0]), Cmd_none()];
}

