import { Union, Record } from "../../.fable/fable-library.3.0.1/Types.js";
import { union_type, record_type, string_type } from "../../.fable/fable-library.3.0.1/Reflection.js";
import { Cmd_OfAsync_start, Cmd_OfAsyncWith_perform, Cmd_none } from "../../.fable/Fable.Elmish.3.1.0/cmd.fs.js";
import { service } from "../../Server.js";

export class Model extends Record {
    constructor(Message) {
        super();
        this.Message = Message;
    }
}

export function Model$reflection() {
    return record_type("DzoukrCz.Client.Pages.Index.State.Model", [], Model, () => [["Message", string_type]]);
}

export class Msg extends Union {
    constructor(tag, ...fields) {
        super();
        this.tag = (tag | 0);
        this.fields = fields;
    }
    cases() {
        return ["GetMessage", "GotMessage"];
    }
}

export function Msg$reflection() {
    return union_type("DzoukrCz.Client.Pages.Index.State.Msg", [], Msg, () => [[], [["Item", string_type]]]);
}

export function init() {
    return [new Model("Click me!"), Cmd_none()];
}

export function update(msg, model) {
    if (msg.tag === 1) {
        return [new Model(msg.fields[0]), Cmd_none()];
    }
    else {
        return [model, Cmd_OfAsyncWith_perform((x) => {
            Cmd_OfAsync_start(x);
        }, service.GetMessage, void 0, (arg0) => (new Msg(1, arg0)))];
    }
}

